using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF Core 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve the old property name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF Core 9 uses only the raw key for the "id" property
            // (e.g. "1") instead of the old "EntityType|Key" format (e.g. "Blog|1").
            // Existing documents have the old format, so we must opt back in.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .HasJsonPropertyName("id")
                  .ToJsonProperty("id");

            // Breaking change 3: Cosmos DB does not support indexes defined by EF Core.
            // EF Core 9 now throws instead of silently ignoring HasIndex().
            // The HasIndex() call has been removed (was a no-op anyway).
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change 2 (continued): Restore the EF8 "EntityType|Key" id format
        // so existing documents with id like "Blog|1" are still found.
        configurationBuilder.Conventions.Add(_ =>
            new Microsoft.EntityFrameworkCore.Metadata.Conventions.IdValueGeneratorConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

